72	const baseTotalForGroup = (group: Item[]): number => {
73	  const type = group[0].type;
74	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
75	    return BLOCK_PREMIUM;
76	  }
77	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
78	};
