88	const CURSED_SURCHARGE_RATE = 0.5;
89	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
90	const HIGH_ENCHANTMENT_THRESHOLD = 5;
91	const LOYALTY_DISCOUNT_RATE = -0.2;
92	const LOYALTY_YEARS_THRESHOLD = 2;
93	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = -0.15;
