117	const itemSurchargeRateFor = (item: Item): number => {
118	  let rate = 0;
119	  if (item.cursed) rate += CURSED_SURCHARGE_RATE;
120	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
121	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
122	  }
123	  return rate;
124	};
125	
126	const itemSurchargesFor = (items: Item[]): number =>
127	  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRateFor(item), 0);
128	
129	const policyModifiersTotal = (baseTotal: number, ctx: QuoteContext): number =>
130	  POLICY_MODIFIERS.reduce(
131	    (sum, mod) => (mod.applies(ctx) ? sum + baseTotal * mod.rate : sum),
132	    0,
133	  );
